import React, { forwardRef } from 'react';
import { useTheme } from '../providers/ThemeProvider';
import { neoBrutalism } from '../styles/tokens';

export type SkeletonVariant = 'text' | 'rectangular' | 'circular';

export interface SkeletonProps extends React.HTMLAttributes<HTMLDivElement> {
  /** Shape variant */
  variant?: SkeletonVariant;
  /** Width (CSS value) */
  width?: string | number;
  /** Height (CSS value) */
  height?: string | number;
  /** Number of lines for text variant */
  lines?: number;
  /** Whether to animate */
  animate?: boolean;
}

/**
 * Skeleton loading placeholder with Neo Brutalism styling.
 *
 * - 2px solid border
 * - Sharp corners for rectangular/text
 * - Pulse animation for loading state
 * - Supports dark/light theme variants
 *
 * @see Requirements 3.7
 */
export const Skeleton = forwardRef<HTMLDivElement, SkeletonProps>(
  (
    {
      variant = 'rectangular',
      width,
      height,
      lines = 1,
      animate = true,
      style,
      ...props
    },
    ref
  ) => {
    const { colors } = useTheme();

    const baseStyle: React.CSSProperties = {
      backgroundColor: colors.border,
      border: `${neoBrutalism.borders.width.default} solid ${colors.border}`,
      opacity: 0.3,
      animation: animate ? 'pulse 1.5s ease-in-out infinite' : undefined,
    };

    const variantStyles: Record<SkeletonVariant, React.CSSProperties> = {
      text: {
        borderRadius: neoBrutalism.borders.radius.none,
        height: height || '16px',
        width: width || '100%',
      },
      rectangular: {
        borderRadius: neoBrutalism.borders.radius.none,
        width: width || '100%',
        height: height || '100px',
      },
      circular: {
        borderRadius: '50%',
        width: width || '48px',
        height: height || '48px',
      },
    };

    if (variant === 'text' && lines > 1) {
      return (
        <div
          ref={ref}
          style={{ display: 'flex', flexDirection: 'column', gap: '8px', ...style }}
          aria-busy="true"
          aria-label="Loading content"
          {...props}
        >
          {Array.from({ length: lines }).map((_, i) => (
            <div
              key={i}
              style={{
                ...baseStyle,
                ...variantStyles.text,
                width: i === lines - 1 ? '70%' : '100%',
              }}
            />
          ))}
        </div>
      );
    }

    return (
      <div
        ref={ref}
        aria-busy="true"
        aria-label="Loading content"
        style={{
          ...baseStyle,
          ...variantStyles[variant],
          ...style,
        }}
        {...props}
      />
    );
  }
);

Skeleton.displayName = 'Skeleton';

'use client';

import React, { forwardRef, useEffect } from 'react';
import { useTheme } from '../providers/ThemeProvider';
import { neoBrutalism } from '../styles/tokens';

export type ToastVariant = 'info' | 'success' | 'warning' | 'error';
export type ToastPosition =
  | 'top-right'
  | 'top-left'
  | 'bottom-right'
  | 'bottom-left'
  | 'top-center'
  | 'bottom-center';

export interface ToastProps extends React.HTMLAttributes<HTMLDivElement> {
  /** Visual variant */
  variant?: ToastVariant;
  /** Toast title */
  title?: string;
  /** Toast message */
  message: string;
  /** Whether the toast is visible */
  visible?: boolean;
  /** Auto-dismiss duration in ms (0 to disable) */
  duration?: number;
  /** Callback when toast should dismiss */
  onDismiss?: () => void;
  /** Position on screen */
  position?: ToastPosition;
}

const positionStyles: Record<ToastPosition, React.CSSProperties> = {
  'top-right': { top: '16px', right: '16px' },
  'top-left': { top: '16px', left: '16px' },
  'bottom-right': { bottom: '16px', right: '16px' },
  'bottom-left': { bottom: '16px', left: '16px' },
  'top-center': { top: '16px', left: '50%', transform: 'translateX(-50%)' },
  'bottom-center': { bottom: '16px', left: '50%', transform: 'translateX(-50%)' },
};

/**
 * Toast notification component with Neo Brutalism styling.
 *
 * - 2px solid border
 * - 4px hard shadow
 * - Sharp corners
 * - Auto-dismiss support
 * - Multiple position options
 * - Supports dark/light theme variants
 *
 * @see Requirements 1.1
 */
export const Toast = forwardRef<HTMLDivElement, ToastProps>(
  (
    {
      variant = 'info',
      title,
      message,
      visible = true,
      duration = 5000,
      onDismiss,
      position = 'top-right',
      style,
      ...props
    },
    ref
  ) => {
    const { mode, colors } = useTheme();
    const shadowColor = neoBrutalism.shadows.color[mode];

    useEffect(() => {
      if (visible && duration > 0 && onDismiss) {
        const timer = setTimeout(onDismiss, duration);
        return () => clearTimeout(timer);
      }
    }, [visible, duration, onDismiss]);

    if (!visible) return null;

    const variantAccents: Record<ToastVariant, string> = {
      info: colors.accentCyan,
      success: colors.accentCyan,
      warning: colors.accentGold,
      error: colors.accentCrimson,
    };

    const accentColor = variantAccents[variant];

    const toastStyle: React.CSSProperties = {
      position: 'fixed',
      zIndex: 10000,
      minWidth: '300px',
      maxWidth: '420px',
      backgroundColor: colors.panel,
      border: `${neoBrutalism.borders.width.default} solid ${colors.border}`,
      borderLeft: `${neoBrutalism.borders.width.heavy} solid ${accentColor}`,
      borderRadius: neoBrutalism.borders.radius.none,
      boxShadow: `${neoBrutalism.shadows.offset.md} ${shadowColor}`,
      padding: '16px',
      display: 'flex',
      flexDirection: 'column',
      gap: '4px',
      ...positionStyles[position],
      ...style,
    };

    const titleStyle: React.CSSProperties = {
      fontFamily: neoBrutalism.typography.body.family,
      fontSize: '14px',
      fontWeight: 700,
      color: colors.textPrimary,
      margin: 0,
    };

    const messageStyle: React.CSSProperties = {
      fontFamily: neoBrutalism.typography.body.family,
      fontSize: '14px',
      color: colors.textSecondary,
      margin: 0,
      lineHeight: neoBrutalism.typography.body.lineHeight,
    };

    const closeButtonStyle: React.CSSProperties = {
      position: 'absolute',
      top: '8px',
      right: '8px',
      width: '24px',
      height: '24px',
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center',
      backgroundColor: 'transparent',
      border: 'none',
      color: colors.textSecondary,
      cursor: 'pointer',
      fontSize: '14px',
      fontWeight: 700,
      padding: 0,
    };

    return (
      <div
        ref={ref}
        role="alert"
        aria-live="polite"
        style={toastStyle}
        {...props}
      >
        {onDismiss && (
          <button
            onClick={onDismiss}
            style={closeButtonStyle}
            aria-label="Dismiss notification"
            type="button"
          >
            ✕
          </button>
        )}
        {title && <p style={titleStyle}>{title}</p>}
        <p style={messageStyle}>{message}</p>
      </div>
    );
  }
);

Toast.displayName = 'Toast';

